  private createGridLines() {
    const positions: number[] = [];
    const offsetX = -(GRID_W * CELL_SIZE) / 2;
    const offsetZ = -(GRID_H * CELL_SIZE) / 2;

    for (let x = 0; x <= GRID_W; x++) {
      positions.push(offsetX + x * CELL_SIZE, 0.01, offsetZ);
      positions.push(offsetX + x * CELL_SIZE, 0.01, offsetZ + GRID_H * CELL_SIZE);
    }
    for (let y = 0; y <= GRID_H; y++) {
      positions.push(offsetX, 0.01, offsetZ + y * CELL_SIZE);
      positions.push(offsetX + GRID_W * CELL_SIZE, 0.01, offsetZ + y * CELL_SIZE);
    }

    const geo = new BufferGeometry();
    geo.setAttribute('position', new Float32BufferAttribute(positions, 3));
    this.gridLines = new LineSegments(geo, MAT.gridLine!);
    this.arenaGroup.add(this.gridLines);
  }

  private createBorderWalls() {
    // Create neon border posts at corners of the arena
    const hw = (GRID_W * CELL_SIZE) / 2;
    const hh = (GRID_H * CELL_SIZE) / 2;

    // Corner posts
    const corners = [[-hw, -hh], [-hw, hh], [hw, -hh], [hw, hh]];
    for (const [cx, cz] of corners) {
      const post = new Mesh(GEO.borderPost!, MAT.borderWall!);
      post.position.set(cx, 0.6, cz);
      this.borderGroup.add(post);

      // Glow caps
      const cap = new Mesh(
        new SphereGeometry(0.1, 8, 8),
        MAT.borderGlow!
      );
      cap.position.set(cx, 1.2, cz);
      this.borderGroup.add(cap);
    }

    // Horizontal bars (top and bottom)
    for (let x = 0; x < GRID_W; x++) {
      const [wx, , _wz] = gridToWorld(x, 0);
      // Top bar
      const barTop = new Mesh(GEO.borderBar!, MAT.borderGlow!);
      barTop.position.set(wx, 1.0, -hh);
      this.borderGroup.add(barTop);
      // Bottom bar
      const barBot = new Mesh(GEO.borderBar!, MAT.borderGlow!);
      barBot.position.set(wx, 1.0, hh);
      this.borderGroup.add(barBot);
    }

    // Vertical bars (left and right)
    for (let y = 0; y < GRID_H; y++) {
      const [_wx, , wz] = gridToWorld(0, y);
      const barLeft = new Mesh(GEO.borderBar!, MAT.borderGlow!);
      barLeft.position.set(-hw, 1.0, wz);
      barLeft.rotation.y = Math.PI / 2;
      this.borderGroup.add(barLeft);
      const barRight = new Mesh(GEO.borderBar!, MAT.borderGlow!);
      barRight.position.set(hw, 1.0, wz);
      barRight.rotation.y = Math.PI / 2;
      this.borderGroup.add(barRight);
    }
  }

  update(delta: number, time: number) {
    this.animTime = time;

    if (this.game.state === GameState.LevelTransition) {
      this.game.update(delta);
      // Animate a brief flash
      this.updateParticles(delta);
      this.updateDeathParticles(delta);
      this.updateTeleportParticles(delta);
      return;
    }

    if (this.game.state !== GameState.Playing) {
      this.handleMenuInput();
      return;
    }

    this.handleGameInput(delta);

    // Update game logic
    const result = this.game.update(delta);

    // Handle events
    for (const bomb of result.exploded) {
      this.onBombExplode(bomb);
    }
    for (const pos of result.destroyed) {
      this.spawnBlockDestroyEffect(pos.x, pos.y);
    }
    for (const enemy of result.enemiesHit) {
      this.spawnEnemyDeathEffect(enemy);
    }
    if (result.enemyTeleported) {
      this.spawnTeleportEffect(result.enemyTeleported);
      this.playTeleportSound();
    }
    if (result.exitRevealedNow) {
      this.createExitMesh();
      this.playExitRevealSound();
    }
    if (result.powerUpsSpawned.length > 0) {
      this.playPowerUpSpawnSound();
    }
    for (const laser of result.laserFired) {
      this.playLaserSound();
      this.shakeTimer = 0.15;
      this.shakeIntensity = 0.08;
    }

    // Rebuild visual grid
    this.rebuildGrid();

    // Update player visual
    this.updatePlayerVisual();

    // Update enemies visual
    this.updateEnemyVisuals();

    // Update bombs visual
    this.updateBombVisuals();

    // Update explosion visuals
    this.updateExplosionVisuals();

    // Update power-up visuals
    this.updatePowerUpVisuals();

    // Update exit tile
    this.updateExitVisual();

    // Update hazard visuals
    this.updateLaserVisuals(time);
    this.updateConveyorVisuals(time);
    this.updateDangerZoneVisuals(time);
    this.updateTrailVisuals();

    // Update particles
    this.updateParticles(delta);
    this.updateDeathParticles(delta);
    this.updateTeleportParticles(delta);

    // Camera shake
    this.updateShake(delta);

    // Animate lights
    for (let i = 0; i < this.lights.length; i++) {
      this.lights[i].intensity = 1.5 + Math.sin(time * 2 + i * 2) * 0.5;
    }

    // Animate border glow
    const borderPulse = Math.sin(time * 1.5) * 0.15 + 0.4;
    MAT.borderGlow!.opacity = borderPulse;

    // Animate starfield
    for (let i = 0; i < this.starfieldStars.length; i++) {
      const star = this.starfieldStars[i];
      const mat = star.material as MeshBasicMaterial;
      mat.opacity = 0.2 + Math.sin(time * (0.5 + (i % 7) * 0.3) + i) * 0.3;
      star.position.y += Math.sin(time * 0.3 + i * 0.1) * 0.002;
    }
  }

  private handleGameInput(delta: number) {
    if (this.inputCooldown > 0) {
      this.inputCooldown -= delta;
      return;
    }

    const kb = this.input.keyboard;
    let dx = 0, dy = 0;

    if (kb.getKeyPressed('KeyW') || kb.getKeyPressed('ArrowUp')) dy = -1;
    else if (kb.getKeyPressed('KeyS') || kb.getKeyPressed('ArrowDown')) dy = 1;
    else if (kb.getKeyPressed('KeyA') || kb.getKeyPressed('ArrowLeft')) dx = -1;
    else if (kb.getKeyPressed('KeyD') || kb.getKeyPressed('ArrowRight')) dx = 1;

    // XR input
    const right = this.input.xr.gamepads.right;
    const left = this.input.xr.gamepads.left;
    if (left) {
      const stick = left.getAxesValues(InputComponent.Thumbstick);
      if (stick) {
        if (Math.abs(stick.x) > 0.5 || Math.abs(stick.y) > 0.5) {
          if (Math.abs(stick.x) > Math.abs(stick.y)) {
            dx = stick.x > 0 ? 1 : -1;
          } else {
            dy = stick.y > 0 ? 1 : -1;
          }
        }
      }
    }

    if (dx !== 0 || dy !== 0) {
      if (this.game.movePlayer(dx, dy, delta)) {
        this.inputCooldown = 0.12;
        this.playMoveSound();
      }
    }

    // Place bomb
    if (kb.getKeyDown('Space') || kb.getKeyDown('KeyE')) {
      if (this.game.placeBomb()) {
        this.playBombPlaceSound();
      }
    }
    if (right?.getButtonDown(InputComponent.Trigger)) {
      if (this.game.placeBomb()) {
        this.playBombPlaceSound();
      }
    }
    if (right?.getButtonDown(InputComponent.A_Button)) {
      if (this.game.placeBomb()) {
        this.playBombPlaceSound();
      }
    }

    // Remote detonate
    if (kb.getKeyDown('KeyR') || right?.getButtonDown(InputComponent.B_Button)) {
      this.game.detonateRemote();
    }

    // Pause
    if (kb.getKeyDown('Escape') || left?.getButtonDown(InputComponent.B_Button)) {
      this.game.state = GameState.Paused;
    }
  }

  private handleMenuInput() {
    // Menu navigation handled by UI system
  }

  private rebuildGrid() {
    let hash = '';
    for (let y = 0; y < GRID_H; y++) {
      for (let x = 0; x < GRID_W; x++) {
        hash += this.game.grid[y][x];
      }
    }
    if (hash === this.lastGridHash) return;
    this.lastGridHash = hash;

    const activeKeys = new Set<string>();

    for (let y = 0; y < GRID_H; y++) {
      for (let x = 0; x < GRID_W; x++) {
        const cell = this.game.grid[y][x];
        const key = `${x}_${y}`;
        const [wx, , wz] = gridToWorld(x, y);

        if (cell === CellType.HardBlock) {
          activeKeys.add(key);
          if (!this.blockMeshes.has(key)) {
            const mesh = new Mesh(GEO.hardBlock!, MAT.hardBlock!);
            mesh.position.set(wx, CELL_SIZE * 0.45, wz);
            this.arenaGroup.add(mesh);
            this.blockMeshes.set(key, mesh);
          }
        } else if (cell === CellType.SoftBlock) {
          activeKeys.add(key);
          if (!this.blockMeshes.has(key)) {
            const mesh = new Mesh(GEO.softBlock!, MAT.softBlock!);
            mesh.position.set(wx, CELL_SIZE * 0.35, wz);
            this.arenaGroup.add(mesh);
            this.blockMeshes.set(key, mesh);
          }
        }
      }
    }

    for (const [key, mesh] of this.blockMeshes) {
      if (!activeKeys.has(key)) {
        this.arenaGroup.remove(mesh);
        this.blockMeshes.delete(key);
      }
    }
  }

  private updatePlayerVisual() {
    const [wx, , wz] = gridToWorld(this.game.playerVisualX, this.game.playerVisualY);
    this.playerGroup.position.set(wx, 0, wz);
    this.playerGroup.visible = true;

    // Shield effect
    if (this.game.hasShield && this.game.shieldTimer > 0) {
      const pulse = Math.sin(this.animTime * 8) * 0.2 + 0.8;
      MAT.playerGlow!.opacity = pulse * 0.8;
      MAT.playerGlow!.color.setHex(0x00ffff);
    } else {
      MAT.playerGlow!.opacity = 0.4 + Math.sin(this.animTime * 3) * 0.2;
      MAT.playerGlow!.color.setHex(0x00ffff);
    }

    // Rotate player slowly
    this.playerGroup.rotation.y = this.animTime * 0.5;
  }

  private updateBombVisuals() {
    const activeKeys = new Set<string>();

    for (const bomb of this.game.bombs) {
      const key = `${bomb.x}_${bomb.y}`;
      activeKeys.add(key);
      const [wx, , wz] = gridToWorld(bomb.x, bomb.y);

      if (!this.bombMeshes.has(key)) {
        const group = new Group();
        const body = new Mesh(GEO.bomb!, MAT.bomb!);
        body.position.y = 0.3;
        group.add(body);

        const glow = new Mesh(
          new SphereGeometry(0.32, 8, 8),
          MAT.bombGlow!.clone()
        );
        glow.position.y = 0.3;
        group.add(glow);

        // Fuse spark
        const spark = new Mesh(
          new SphereGeometry(0.05, 6, 6),
          new MeshBasicMaterial({ color: 0xffcc00, blending: AdditiveBlending })
        );
        spark.position.set(0, 0.55, 0);
        group.add(spark);

        group.position.set(wx, 0, wz);
        this.arenaGroup.add(group);
        this.bombMeshes.set(key, group);
      }

      const group = this.bombMeshes.get(key)!;
      const urgency = 1 - bomb.timer / 3;
      const pulse = Math.sin(this.animTime * (5 + urgency * 15)) * 0.5 + 0.5;
      const glow = group.children[1] as Mesh;
      (glow.material as MeshBasicMaterial).opacity = 0.3 + pulse * 0.5;
      group.children[0].scale.setScalar(0.9 + pulse * 0.15);

      // Fuse spark flicker
      const spark = group.children[2];
      if (spark) {
        spark.position.y = 0.55 + Math.sin(this.animTime * 20) * 0.02;
        (spark as Mesh).material = new MeshBasicMaterial({
          color: urgency > 0.7 ? 0xff0000 : 0xffcc00,
          blending: AdditiveBlending,
        });
        spark.visible = Math.sin(this.animTime * 30) > -0.3;
      }

      MAT.bomb!.emissiveIntensity = 0.3 + urgency * 0.7;
    }

    for (const [key, group] of this.bombMeshes) {
      if (!activeKeys.has(key)) {
        this.arenaGroup.remove(group);
        this.bombMeshes.delete(key);
      }
    }
  }

  private updateExplosionVisuals() {
    const activeKeys = new Set<string>();

    for (const exp of this.game.explosions) {
      const key = `${exp.x}_${exp.y}`;
      activeKeys.add(key);
      const [wx, , wz] = gridToWorld(exp.x, exp.y);

      if (!this.explosionMeshes.has(key)) {
        const mesh = new Mesh(GEO.explosion!, MAT.explosion!.clone());
        mesh.position.set(wx, 0.4, wz);
        this.arenaGroup.add(mesh);
        this.explosionMeshes.set(key, mesh);
      }

      const mesh = this.explosionMeshes.get(key)!;
      const life = exp.timer / 0.5;
      mesh.scale.setScalar(0.5 + life * 0.5);
      (mesh.material as MeshBasicMaterial).opacity = life * 0.9;

      const c = new Color();
      c.setHSL(0.08 * life, 1, 0.5 + life * 0.3);
      (mesh.material as MeshBasicMaterial).color = c;
    }

    for (const [key, mesh] of this.explosionMeshes) {
      if (!activeKeys.has(key)) {
        this.arenaGroup.remove(mesh);
        this.explosionMeshes.delete(key);
      }
    }
  }

  private updateEnemyVisuals() {
    const activeIds = new Set<number>();

    for (let i = 0; i < this.game.enemies.length; i++) {
      const enemy = this.game.enemies[i];
      if (!enemy.alive) {
        if (this.enemyMeshes.has(i)) {
          this.arenaGroup.remove(this.enemyMeshes.get(i)!);
          this.enemyMeshes.delete(i);
        }
        continue;
      }
      activeIds.add(i);
      const [wx, , wz] = gridToWorld(enemy.visualX, enemy.visualY);

      if (!this.enemyMeshes.has(i)) {
        const group = new Group();
        const mat = this.getEnemyMaterial(enemy.type);

        if (enemy.type === 'teleporter') {
          const body = new Mesh(GEO.enemyTeleporter!, mat);
          body.position.y = 0.35;
          group.add(body);

          // Teleporter has a ring
          const ring = new Mesh(
            new CylinderGeometry(0.35, 0.35, 0.04, 12),
            MAT.enemyTeleporter!.clone()
          );
          ring.position.y = 0.15;
          group.add(ring);
        } else {
          const body = new Mesh(GEO.enemy!, mat);
          body.position.y = 0.35;
          group.add(body);
        }

        // Eyes
        const eyeMat = new MeshBasicMaterial({ color: 0xffffff });
        const eyeGeo = new SphereGeometry(0.06, 6, 6);
        const eye1 = new Mesh(eyeGeo, eyeMat);
        eye1.position.set(-0.1, 0.45, -0.22);
        group.add(eye1);
        const eye2 = new Mesh(eyeGeo, eyeMat);
        eye2.position.set(0.1, 0.45, -0.22);
        group.add(eye2);

        // HP indicator for multi-hp enemies
        if (enemy.hp > 1) {
          const hpMat = new MeshBasicMaterial({ color: 0xffffff, transparent: true, opacity: 0.8 });
          const hpGeo = new SphereGeometry(0.04, 6, 6);
          for (let h = 0; h < enemy.hp; h++) {
            const dot = new Mesh(hpGeo, hpMat);
            dot.position.set((h - (enemy.hp - 1) / 2) * 0.12, 0.7, 0);
            group.add(dot);
          }
        }

        this.arenaGroup.add(group);
        this.enemyMeshes.set(i, group);
      }

      const group = this.enemyMeshes.get(i)!;
      group.position.set(wx, 0, wz);

      // Animations per type
      if (enemy.type === 'patrol') {
        group.children[0].position.y = 0.35;
        group.rotation.y = (enemy.patrolDir * Math.PI) / 2;
      } else if (enemy.type === 'teleporter') {
        group.children[0].position.y = 0.35 + Math.sin(this.animTime * 5 + i) * 0.08;
        if (group.children[1]) {
          group.children[1].rotation.y = this.animTime * 3;
        }
      } else {
        group.children[0].position.y = 0.35 + Math.sin(this.animTime * 4 + i) * 0.05;
        group.rotation.y = Math.sin(this.animTime * 2 + i * 3) * 0.3;
      }
    }

    for (const [id, group] of this.enemyMeshes) {
      if (!activeIds.has(id)) {
        this.arenaGroup.remove(group);
        this.enemyMeshes.delete(id);
      }
    }
  }

  private getEnemyMaterial(type: EnemyData['type']): MeshStandardMaterial {
    switch (type) {
      case 'chase': return MAT.enemyChase!;
      case 'bomber': return MAT.enemyBomber!;
      case 'patrol': return MAT.enemyPatrol!;
      case 'teleporter': return MAT.enemyTeleporter!;
      default: return MAT.enemyWander!;
    }
  }

  private updatePowerUpVisuals() {
    const activeKeys = new Set<string>();

    for (const pu of this.game.powerUps) {
      if (pu.collected) continue;
      const key = `${pu.x}_${pu.y}`;
      activeKeys.add(key);
      const [wx, , wz] = gridToWorld(pu.x, pu.y);

      if (!this.powerUpMeshes.has(key)) {
        const group = new Group();
        const mat = MAT.powerUp.get(pu.type) || MAT.powerUp.get(0)!;
        const sphere = new Mesh(GEO.powerUp!, mat);
        sphere.position.y = 0.4;
        group.add(sphere);

        const ring = new Mesh(
          new CylinderGeometry(0.25, 0.25, 0.02, 12),
          mat.clone()
        );
        ring.position.y = 0.15;
        group.add(ring);

        group.position.set(wx, 0, wz);
        this.arenaGroup.add(group);
        this.powerUpMeshes.set(key, group);
      }

      const group = this.powerUpMeshes.get(key)!;
      group.children[0].position.y = 0.4 + Math.sin(this.animTime * 3) * 0.1;
      group.children[0].rotation.y = this.animTime * 2;
      group.children[1].rotation.y = -this.animTime * 1.5;
    }

    for (const [key, group] of this.powerUpMeshes) {
      if (!activeKeys.has(key)) {
        this.arenaGroup.remove(group);
        this.powerUpMeshes.delete(key);
      }
    }
  }

  private createExitMesh() {
    if (this.exitMesh) {
      this.arenaGroup.remove(this.exitMesh);
    }
    const [wx, , wz] = gridToWorld(this.game.exitX, this.game.exitY);
    this.exitMesh = new Mesh(GEO.exitTile!, MAT.exitTile!);
    this.exitMesh.position.set(wx, 0.03, wz);
    this.arenaGroup.add(this.exitMesh);
  }

  private updateExitVisual() {
    if (!this.exitMesh || !this.game.exitRevealed) return;
    this.exitMesh.rotation.y = this.animTime * 2;
    MAT.exitTile!.opacity = 0.5 + Math.sin(this.animTime * 4) * 0.3;
    this.exitMesh.scale.setScalar(0.8 + Math.sin(this.animTime * 3) * 0.2);
  }

  private onBombExplode(_bomb: BombData) {
    this.shakeTimer = 0.3;
    this.shakeIntensity = 0.15;
    this.playExplosionSound();
  }

  private spawnBlockDestroyEffect(gx: number, gy: number) {
    const [wx, , wz] = gridToWorld(gx, gy);
    for (let i = 0; i < 6; i++) {
      const size = 0.05 + Math.random() * 0.1;
      const geo = new BoxGeometry(size, size, size);
      const mat = new MeshBasicMaterial({
        color: new Color().setHSL(0.08 + Math.random() * 0.05, 0.8, 0.5),
        transparent: true,
        opacity: 1,
        blending: AdditiveBlending,
      });
      const mesh = new Mesh(geo, mat);
      mesh.position.set(
        wx + (Math.random() - 0.5) * 0.3,
        0.3 + Math.random() * 0.3,
        wz + (Math.random() - 0.5) * 0.3
      );
      this.arenaGroup.add(mesh);
      this.explosionParticles.push({
        mesh,
        vel: new Vector3(
          (Math.random() - 0.5) * 3,
          2 + Math.random() * 3,
          (Math.random() - 0.5) * 3
        ),
        life: 0.8 + Math.random() * 0.4,
      });
    }
  }

  private spawnEnemyDeathEffect(enemy: EnemyData) {
    const [wx, , wz] = gridToWorld(enemy.visualX, enemy.visualY);
    const deathColor = this.getEnemyDeathColor(enemy.type);
    for (let i = 0; i < 10; i++) {
      const size = 0.06 + Math.random() * 0.08;
      const geo = new BoxGeometry(size, size, size);
      const mat = new MeshBasicMaterial({
        color: deathColor,
        transparent: true,
        opacity: 1,
        blending: AdditiveBlending,
      });
      const mesh = new Mesh(geo, mat);
      mesh.position.set(
        wx + (Math.random() - 0.5) * 0.3,
        0.3 + Math.random() * 0.4,
        wz + (Math.random() - 0.5) * 0.3
      );
      this.arenaGroup.add(mesh);
      this.deathParticles.push({
        mesh,
        vel: new Vector3(
          (Math.random() - 0.5) * 4,
          3 + Math.random() * 3,
          (Math.random() - 0.5) * 4
        ),
        life: 1.0 + Math.random() * 0.5,
        color: deathColor,
      });
    }
    this.playEnemyDeathSound(enemy.type);
  }

  private getEnemyDeathColor(type: EnemyData['type']): number {
    switch (type) {
      case 'chase': return 0xff0000;
      case 'bomber': return 0xff8800;
      case 'patrol': return 0x8844ff;
      case 'teleporter': return 0x00ff88;
      default: return 0xff4488;
    }
  }

  private spawnTeleportEffect(enemy: EnemyData) {
    const [wx, , wz] = gridToWorld(enemy.visualX, enemy.visualY);
    for (let i = 0; i < 8; i++) {
      const size = 0.04 + Math.random() * 0.06;
      const geo = new SphereGeometry(size, 6, 6);
      const mat = new MeshBasicMaterial({
        color: 0x00ff88,
        transparent: true,
        opacity: 1,
        blending: AdditiveBlending,
      });
      const mesh = new Mesh(geo, mat);
      const angle = (i / 8) * Math.PI * 2;
      mesh.position.set(
        wx + Math.cos(angle) * 0.4,
        0.3 + Math.random() * 0.5,
        wz + Math.sin(angle) * 0.4
      );
      this.arenaGroup.add(mesh);
      this.teleportParticles.push({
        mesh,
        vel: new Vector3(
          Math.cos(angle) * 1.5,
          2 + Math.random() * 2,
          Math.sin(angle) * 1.5
        ),
        life: 0.6 + Math.random() * 0.4,
      });
    }
  }

  private updateParticles(delta: number) {
    for (let i = this.explosionParticles.length - 1; i >= 0; i--) {
      const p = this.explosionParticles[i];
      p.life -= delta;
      if (p.life <= 0) {
        this.arenaGroup.remove(p.mesh);
        this.explosionParticles.splice(i, 1);
        continue;
      }
      p.vel.y -= 9.8 * delta;
      p.mesh.position.add(p.vel.clone().multiplyScalar(delta));
      (p.mesh.material as MeshBasicMaterial).opacity = p.life;
      p.mesh.rotation.x += delta * 5;
      p.mesh.rotation.z += delta * 3;
    }
  }

  private updateDeathParticles(delta: number) {
    for (let i = this.deathParticles.length - 1; i >= 0; i--) {
      const p = this.deathParticles[i];
      p.life -= delta;
      if (p.life <= 0) {
        this.arenaGroup.remove(p.mesh);
        this.deathParticles.splice(i, 1);
        continue;
      }
      p.vel.y -= 7 * delta;
      p.mesh.position.add(p.vel.clone().multiplyScalar(delta));
      (p.mesh.material as MeshBasicMaterial).opacity = p.life * 0.8;
      p.mesh.scale.setScalar(0.5 + p.life * 0.5);
    }
  }

  private updateTeleportParticles(delta: number) {
    for (let i = this.teleportParticles.length - 1; i >= 0; i--) {
      const p = this.teleportParticles[i];
      p.life -= delta;
      if (p.life <= 0) {
        this.arenaGroup.remove(p.mesh);
        this.teleportParticles.splice(i, 1);
        continue;
      }
      p.vel.y -= 3 * delta;
      p.mesh.position.add(p.vel.clone().multiplyScalar(delta));
      (p.mesh.material as MeshBasicMaterial).opacity = p.life;
      p.mesh.scale.setScalar(p.life);
    }
  }

  private updateShake(delta: number) {
    if (this.shakeTimer > 0) {
      this.shakeTimer -= delta;
      const shake = this.shakeIntensity * (this.shakeTimer / 0.3);
      this.camera.position.set(
        this.cameraBasePos.x + (Math.random() - 0.5) * shake,
        this.cameraBasePos.y + (Math.random() - 0.5) * shake * 0.5,
        this.cameraBasePos.z + (Math.random() - 0.5) * shake
      );
    }
  }

  showGame() {
    this.playerGroup.visible = true;
    this.arenaGroup.visible = true;
    this.lastGridHash = ''; // Force rebuild
  }

  hideGame() {
    this.playerGroup.visible = false;
    for (const [, mesh] of this.blockMeshes) this.arenaGroup.remove(mesh);
    this.blockMeshes.clear();
    for (const [, mesh] of this.bombMeshes) this.arenaGroup.remove(mesh);
    this.bombMeshes.clear();
    for (const [, mesh] of this.explosionMeshes) this.arenaGroup.remove(mesh);
    this.explosionMeshes.clear();
    for (const [, mesh] of this.enemyMeshes) this.arenaGroup.remove(mesh);
    this.enemyMeshes.clear();
    for (const [, mesh] of this.powerUpMeshes) this.arenaGroup.remove(mesh);
    this.powerUpMeshes.clear();
    for (const [, group] of this.laserMeshes) this.arenaGroup.remove(group);
    this.laserMeshes.clear();
    for (const [, meshes] of this.laserWarningMeshes) {
      for (const m of meshes) this.arenaGroup.remove(m);
    }
    this.laserWarningMeshes.clear();
    for (const [, group] of this.conveyorMeshes) this.arenaGroup.remove(group);
    this.conveyorMeshes.clear();
    for (const m of this.dangerZoneMeshes) this.arenaGroup.remove(m);
    this.dangerZoneMeshes = [];
    for (const m of this.trailMeshes) this.arenaGroup.remove(m);
    this.trailMeshes = [];
    if (this.exitMesh) {
      this.arenaGroup.remove(this.exitMesh);
      this.exitMesh = null;
    }
    this.lastGridHash = '';
  }

  applyTheme() {
    const theme = this.game.currentTheme;
    MAT.floor!.color.setHex(theme.floorColor);
    MAT.gridLine!.color.setHex(theme.gridColor);
    MAT.playerGlow!.color.setHex(theme.accentColor);
    MAT.borderGlow!.color.setHex(theme.gridColor);
    MAT.borderWall!.emissive.setHex(theme.gridColor);
    this.scene.background = new Color(theme.floorColor);
    if (this.scene.fog) {
      (this.scene.fog as FogExp2).color.setHex(theme.floorColor);
    }
  }

  // --- Hazard visuals ---

  private updateLaserVisuals(time: number) {
    // Clean up old laser meshes
    for (const [, group] of this.laserMeshes) {
      this.arenaGroup.remove(group);
    }
    this.laserMeshes.clear();
    for (const [, meshes] of this.laserWarningMeshes) {
      for (const m of meshes) this.arenaGroup.remove(m);
    }
    this.laserWarningMeshes.clear();

    for (let li = 0; li < this.game.lasers.length; li++) {
      const laser = this.game.lasers[li];

      if (laser.active) {
        // Draw active laser beam
        const group = new Group();
        const beamMat = new MeshBasicMaterial({
          color: 0xff0044,
          transparent: true,
          opacity: 0.6 + Math.sin(time * 30) * 0.3,
          blending: AdditiveBlending,
        });

        if (laser.axis === 'row') {
          for (let x = 1; x < GRID_W - 1; x++) {
            const [wx, , wz] = gridToWorld(x, laser.index);
            const beam = new Mesh(new BoxGeometry(CELL_SIZE * 0.8, 0.6, 0.08), beamMat);
            beam.position.set(wx, 0.3, wz);
            group.add(beam);
          }
        } else {
          for (let y = 1; y < GRID_H - 1; y++) {
            const [wx, , wz] = gridToWorld(laser.index, y);
            const beam = new Mesh(new BoxGeometry(0.08, 0.6, CELL_SIZE * 0.8), beamMat);
            beam.position.set(wx, 0.3, wz);
            group.add(beam);
          }
        }
        this.arenaGroup.add(group);
        this.laserMeshes.set(li, group);
      } else if (laser.warningTimer > 0) {
        // Draw warning indicators
        const meshes: Mesh[] = [];
        const warningMat = new MeshBasicMaterial({
          color: 0xff4400,
          transparent: true,
          opacity: 0.15 + Math.sin(time * 6) * 0.1,
          blending: AdditiveBlending,
        });

        if (laser.axis === 'row') {
          for (let x = 1; x < GRID_W - 1; x++) {
            const [wx, , wz] = gridToWorld(x, laser.index);
            const warn = new Mesh(new BoxGeometry(CELL_SIZE * 0.9, 0.02, CELL_SIZE * 0.9), warningMat);
            warn.position.set(wx, 0.02, wz);
            this.arenaGroup.add(warn);
            meshes.push(warn);
          }
        } else {
          for (let y = 1; y < GRID_H - 1; y++) {
            const [wx, , wz] = gridToWorld(laser.index, y);
            const warn = new Mesh(new BoxGeometry(CELL_SIZE * 0.9, 0.02, CELL_SIZE * 0.9), warningMat);
            warn.position.set(wx, 0.02, wz);
            this.arenaGroup.add(warn);
            meshes.push(warn);
          }
        }
        this.laserWarningMeshes.set(li, meshes);
      }
    }
  }

  private updateConveyorVisuals(time: number) {
    const activeKeys = new Set<string>();

    for (const conv of this.game.conveyors) {
      const key = `${conv.x}_${conv.y}`;
      activeKeys.add(key);
      const [wx, , wz] = gridToWorld(conv.x, conv.y);

      if (!this.conveyorMeshes.has(key)) {
        const group = new Group();
        // Base tile
        const baseMat = new MeshBasicMaterial({
          color: 0x4444ff,
          transparent: true,
          opacity: 0.4,
          blending: AdditiveBlending,
        });
        const base = new Mesh(new BoxGeometry(CELL_SIZE * 0.85, 0.03, CELL_SIZE * 0.85), baseMat);
        base.position.y = 0.02;
        group.add(base);

        // Arrow indicators (3 small triangles pointing in direction)
        const arrowMat = new MeshBasicMaterial({
          color: 0x8888ff,
          transparent: true,
          opacity: 0.7,
          blending: AdditiveBlending,
        });
        for (let a = 0; a < 3; a++) {
          const arrow = new Mesh(
            new CylinderGeometry(0, 0.08, 0.15, 3),
            arrowMat
          );
          const offset = (a - 1) * 0.25;
          arrow.position.set(
            conv.dx === 0 ? offset : conv.dx * (a - 1) * 0.2,
            0.1,
            conv.dy === 0 ? offset : conv.dy * (a - 1) * 0.2
          );
          // Rotate arrow to point in conveyor direction
          if (conv.dx > 0) arrow.rotation.z = -Math.PI / 2;
          else if (conv.dx < 0) arrow.rotation.z = Math.PI / 2;
          else if (conv.dy > 0) arrow.rotation.x = Math.PI;
          // dy < 0 is default orientation
          group.add(arrow);
        }

        group.position.set(wx, 0, wz);
        this.arenaGroup.add(group);
        this.conveyorMeshes.set(key, group);
      }

      // Animate arrows
      const group = this.conveyorMeshes.get(key)!;
      for (let a = 1; a <= 3; a++) {
        if (group.children[a]) {
          const phase = (time * 3 + a * 0.5) % 1;
          (group.children[a] as Mesh).material = new MeshBasicMaterial({
            color: 0x8888ff,
            transparent: true,
            opacity: 0.3 + phase * 0.5,
            blending: AdditiveBlending,
          });
        }
      }
    }

    for (const [key, group] of this.conveyorMeshes) {
      if (!activeKeys.has(key)) {
        this.arenaGroup.remove(group);
        this.conveyorMeshes.delete(key);
      }
    }
  }

  private updateDangerZoneVisuals(time: number) {
    // Remove old danger zone meshes
    for (const m of this.dangerZoneMeshes) {
      this.arenaGroup.remove(m);
    }
    this.dangerZoneMeshes = [];

    const dangerMat = new MeshBasicMaterial({
      color: 0xff2200,
      transparent: true,
      opacity: 0.06 + Math.sin(time * 4) * 0.04,
      blending: AdditiveBlending,
    });

    for (const zone of this.game.dangerZones) {
      for (const cell of zone.cells) {
        const [wx, , wz] = gridToWorld(cell.x, cell.y);
        const mesh = new Mesh(new BoxGeometry(CELL_SIZE * 0.85, 0.02, CELL_SIZE * 0.85), dangerMat);
        mesh.position.set(wx, 0.015, wz);
        this.arenaGroup.add(mesh);
        this.dangerZoneMeshes.push(mesh);
      }
    }
  }

  private updateTrailVisuals() {
    // Remove old trail meshes
    for (const m of this.trailMeshes) {
      this.arenaGroup.remove(m);
    }
    this.trailMeshes = [];

    for (const t of this.game.playerTrail) {
      const alpha = 1 - t.age / 0.5;
      if (alpha <= 0) continue;
      const mat = new MeshBasicMaterial({
        color: 0x00ffff,
        transparent: true,
        opacity: alpha * 0.3,
        blending: AdditiveBlending,
      });
      const [wx, , wz] = gridToWorld(t.x, t.y);
      const mesh = new Mesh(new SphereGeometry(0.08 * alpha, 6, 6), mat);
      mesh.position.set(wx, 0.1, wz);
      this.arenaGroup.add(mesh);
      this.trailMeshes.push(mesh);
    }
  }

  // --- Procedural audio ---
  private audioCtx: AudioContext | null = null;

  private getAudioCtx(): AudioContext {
    if (!this.audioCtx) {
      this.audioCtx = new AudioContext();
    }
    return this.audioCtx;
  }

  private playTone(freq: number, duration: number, volume: number, type: OscillatorType = 'square') {
    try {
      const ctx = this.getAudioCtx();
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.type = type;
      osc.frequency.setValueAtTime(freq, ctx.currentTime);
      gain.gain.setValueAtTime(volume * this.game.sfxVolume, ctx.currentTime);
      gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + duration);
      osc.connect(gain);
      gain.connect(ctx.destination);
      osc.start();
      osc.stop(ctx.currentTime + duration);
    } catch { /* audio may not be available */ }
  }

  private playNoise(duration: number, volume: number) {
    try {
      const ctx = this.getAudioCtx();
      const bufferSize = Math.floor(ctx.sampleRate * duration);
      const buffer = ctx.createBuffer(1, bufferSize, ctx.sampleRate);
      const data = buffer.getChannelData(0);
      for (let i = 0; i < bufferSize; i++) {
        data[i] = (Math.random() * 2 - 1) * Math.pow(1 - i / bufferSize, 2);
      }
      const source = ctx.createBufferSource();
      source.buffer = buffer;
      const gain = ctx.createGain();
      gain.gain.setValueAtTime(volume * this.game.sfxVolume, ctx.currentTime);
      source.connect(gain);
      gain.connect(ctx.destination);
      source.start();
    } catch { /* audio may not be available */ }
  }

  playMoveSound() {
    this.playTone(440, 0.05, 0.1, 'sine');
  }

  playBombPlaceSound() {
    this.playTone(220, 0.15, 0.2, 'square');
    this.playTone(165, 0.2, 0.15, 'square');
  }

  playExplosionSound() {
    this.playNoise(0.4, 0.4);
    this.playTone(80, 0.3, 0.3, 'sawtooth');
  }

  playPowerUpSound() {
    this.playTone(660, 0.1, 0.15, 'sine');
    setTimeout(() => this.playTone(880, 0.1, 0.15, 'sine'), 50);
    setTimeout(() => this.playTone(1100, 0.15, 0.12, 'sine'), 100);
  }

  playDeathSound() {
    this.playTone(440, 0.15, 0.3, 'sawtooth');
    setTimeout(() => this.playTone(330, 0.15, 0.25, 'sawtooth'), 100);
    setTimeout(() => this.playTone(220, 0.3, 0.2, 'sawtooth'), 200);
  }

  playVictorySound() {
    const notes = [523, 659, 784, 1047];
    notes.forEach((n, i) => {
      setTimeout(() => this.playTone(n, 0.2, 0.15, 'sine'), i * 150);
    });
  }

  private playEnemyDeathSound(type: EnemyData['type']) {
    if (type === 'teleporter') {
      this.playTone(800, 0.1, 0.2, 'sine');
      setTimeout(() => this.playTone(400, 0.2, 0.15, 'sine'), 50);
    } else if (type === 'bomber') {
      this.playNoise(0.2, 0.3);
      this.playTone(150, 0.2, 0.2, 'sawtooth');
    } else {
      this.playTone(300, 0.1, 0.2, 'square');
      setTimeout(() => this.playTone(200, 0.15, 0.15, 'square'), 60);
    }
  }

  private playTeleportSound() {
    this.playTone(1200, 0.05, 0.1, 'sine');
    setTimeout(() => this.playTone(600, 0.1, 0.1, 'sine'), 30);
    setTimeout(() => this.playTone(1500, 0.08, 0.08, 'sine'), 80);
  }

  private playExitRevealSound() {
    this.playTone(440, 0.15, 0.15, 'sine');
    setTimeout(() => this.playTone(660, 0.15, 0.15, 'sine'), 100);
    setTimeout(() => this.playTone(880, 0.2, 0.12, 'sine'), 200);
  }

  private playPowerUpSpawnSound() {
    this.playTone(550, 0.08, 0.08, 'sine');
  }

  playLevelCompleteSound() {
    const notes = [440, 554, 659, 880];
    notes.forEach((n, i) => {
      setTimeout(() => this.playTone(n, 0.15, 0.12, 'sine'), i * 120);
    });
  }

  playComboSound(count: number) {
    const freq = 400 + count * 80;
    this.playTone(Math.min(freq, 1600), 0.08, 0.1, 'sine');
  }

  private playLaserSound() {
    this.playTone(150, 0.3, 0.25, 'sawtooth');
    this.playTone(200, 0.2, 0.15, 'square');
    this.playNoise(0.15, 0.2);
  }

  playConveyorSound() {
    this.playTone(180, 0.08, 0.06, 'sine');
  }

  playMultiplierSound(mult: number) {
    const freq = 500 + mult * 100;
    this.playTone(freq, 0.12, 0.1, 'sine');
    setTimeout(() => this.playTone(freq * 1.5, 0.1, 0.08, 'sine'), 60);
  }
}

import {
  createSystem,
  PanelUI,
  PanelDocument,
  UIKitDocument,
  UIKit,
  eq,
  Entity,
  Follower,
} from '@iwsdk/core';
import { GameManager, GameState, GameMode } from './game';
import { GameSystem } from './game-system';

const getDoc = (e: Entity) =>
  e.getValue(PanelDocument, 'document') as UIKitDocument | undefined;

const setText = (doc: UIKitDocument | undefined, id: string, text: string) =>
  (doc?.getElementById(id) as any)?.setProperties({ text });

const setColor = (doc: UIKitDocument | undefined, id: string, color: string) =>
  (doc?.getElementById(id) as any)?.setProperties({ color });

const onClick = (doc: UIKitDocument, id: string, cb: () => void) => {
  const el = doc.getElementById(id) as any;
  el?.addEventListener('click', cb);
};

export class GameUISystem extends createSystem({
  hud: {
    required: [PanelUI, PanelDocument],
    where: [eq(PanelUI, 'config', './ui/hud.json')],
  },
  menu: {
    required: [PanelUI, PanelDocument],
    where: [eq(PanelUI, 'config', './ui/menu.json')],
  },
  gameover: {
    required: [PanelUI, PanelDocument],
    where: [eq(PanelUI, 'config', './ui/gameover.json')],
  },
  settings: {
    required: [PanelUI, PanelDocument],
    where: [eq(PanelUI, 'config', './ui/settings.json')],
  },
  pause: {
    required: [PanelUI, PanelDocument],
    where: [eq(PanelUI, 'config', './ui/pause.json')],
  },
  achievements: {
    required: [PanelUI, PanelDocument],
    where: [eq(PanelUI, 'config', './ui/achvmts.json')],
  },
  powerups: {
    required: [PanelUI, PanelDocument],
    where: [eq(PanelUI, 'config', './ui/powerups.json')],
  },
  transition: {
    required: [PanelUI, PanelDocument],
    where: [eq(PanelUI, 'config', './ui/leveltransition.json')],
  },
  howto: {
    required: [PanelUI, PanelDocument],
    where: [eq(PanelUI, 'config', './ui/howto.json')],
  },
}) {
  private game!: GameManager;
  private gameSystem!: GameSystem;
  private hudEntity!: Entity;
  private menuEntity!: Entity;
  private gameoverEntity!: Entity;
  private settingsEntity!: Entity;
  private pauseEntity!: Entity;
  private achievementsEntity!: Entity;
  private powerupsEntity!: Entity;
  private transitionEntity!: Entity;
  private howtoEntity!: Entity;

  private hudDoc: UIKitDocument | null = null;
  private menuDoc: UIKitDocument | null = null;
  private gameoverDoc: UIKitDocument | null = null;
  private settingsDoc: UIKitDocument | null = null;
  private pauseDoc: UIKitDocument | null = null;
  private achievementsDoc: UIKitDocument | null = null;
  private powerupsDoc: UIKitDocument | null = null;
  private transitionDoc: UIKitDocument | null = null;
  private howtoDoc: UIKitDocument | null = null;

  private lastState: GameState = GameState.Menu;
  private lastCombo = 0;
  private lastMultiplier = 1;

  setRefs(refs: { game: GameManager; gameSystem: GameSystem }) {
    this.game = refs.game;
    this.gameSystem = refs.gameSystem;
  }

  setPanelEntities(
    hud: Entity, menu: Entity, gameover: Entity, settings: Entity,
    pause: Entity, achievements: Entity, powerups: Entity, transition: Entity,
    howto: Entity
  ) {
    this.hudEntity = hud;
    this.menuEntity = menu;
    this.gameoverEntity = gameover;
    this.settingsEntity = settings;
    this.pauseEntity = pause;
    this.achievementsEntity = achievements;
    this.powerupsEntity = powerups;
    this.transitionEntity = transition;
    this.howtoEntity = howto;
  }

  init() {
    this.queries.hud.subscribe('qualify', (entity) => {
      this.hudDoc = getDoc(entity) || null;
    });

    this.queries.menu.subscribe('qualify', (entity) => {
      this.menuDoc = getDoc(entity) || null;
      if (this.menuDoc) this.wireMenuButtons();
    });

    this.queries.gameover.subscribe('qualify', (entity) => {
      this.gameoverDoc = getDoc(entity) || null;
      if (this.gameoverDoc) this.wireGameoverButtons();
    });

    this.queries.settings.subscribe('qualify', (entity) => {
      this.settingsDoc = getDoc(entity) || null;
      if (this.settingsDoc) this.wireSettingsButtons();
    });

    this.queries.pause.subscribe('qualify', (entity) => {
      this.pauseDoc = getDoc(entity) || null;
      if (this.pauseDoc) this.wirePauseButtons();
    });

    this.queries.achievements.subscribe('qualify', (entity) => {
      this.achievementsDoc = getDoc(entity) || null;
      if (this.achievementsDoc) this.wireAchievementsButtons();
    });

    this.queries.powerups.subscribe('qualify', (entity) => {
      this.powerupsDoc = getDoc(entity) || null;
    });

    this.queries.transition.subscribe('qualify', (entity) => {
      this.transitionDoc = getDoc(entity) || null;
    });

    this.queries.howto.subscribe('qualify', (entity) => {
      this.howtoDoc = getDoc(entity) || null;
      if (this.howtoDoc) this.wireHowtoButtons();
    });
  }

  private wireMenuButtons() {
    const doc = this.menuDoc!;

    onClick(doc, 'btn-classic', () => {
      this.game.startGame(GameMode.Classic);
      this.gameSystem.showGame();
      this.gameSystem.applyTheme();
      this.showPanel('playing');
    });

    onClick(doc, 'btn-timed', () => {
      this.game.startGame(GameMode.Timed);
      this.gameSystem.showGame();
      this.gameSystem.applyTheme();
      this.showPanel('playing');
    });

    onClick(doc, 'btn-survival', () => {
      this.game.startGame(GameMode.Survival);
      this.gameSystem.showGame();
      this.gameSystem.applyTheme();
      this.showPanel('playing');
    });

    onClick(doc, 'btn-puzzle', () => {
      this.game.startGame(GameMode.Puzzle);
      this.gameSystem.showGame();
      this.gameSystem.applyTheme();
      this.showPanel('playing');
    });

    onClick(doc, 'btn-settings', () => {
      this.showPanel('settings');
    });

    onClick(doc, 'btn-menu-ach', () => {
      this.updateAchievementsDisplay();
      this.showPanel('achievements');
    });

    onClick(doc, 'btn-howto', () => {
      this.showPanel('howto');
    });
  }

  private wireGameoverButtons() {
    const doc = this.gameoverDoc!;

    onClick(doc, 'btn-retry', () => {
      this.game.startGame(this.game.mode);
      this.gameSystem.showGame();
      this.showPanel('playing');
    });

    onClick(doc, 'btn-menu', () => {
      this.game.state = GameState.Menu;
      this.gameSystem.hideGame();
      this.showPanel('menu');
    });
  }

  private wireSettingsButtons() {
    const doc = this.settingsDoc!;

    onClick(doc, 'btn-back', () => {
      this.showPanel('menu');
    });

    onClick(doc, 'btn-easy', () => {
      this.game.difficulty = 0;
      this.updateSettingsDisplay();
    });

    onClick(doc, 'btn-normal', () => {
      this.game.difficulty = 1;
      this.updateSettingsDisplay();
    });

    onClick(doc, 'btn-hard', () => {
      this.game.difficulty = 2;
      this.updateSettingsDisplay();
    });

    for (let i = 0; i < this.game.themes.length; i++) {
      onClick(doc, `btn-theme-${i}`, () => {
        this.game.themeIndex = i;
        this.gameSystem.applyTheme();
        this.updateSettingsDisplay();
      });
    }
  }

  private wirePauseButtons() {
    const doc = this.pauseDoc!;

    onClick(doc, 'btn-resume', () => {
      this.game.state = GameState.Playing;
      this.showPanel('playing');
    });

    onClick(doc, 'btn-achievements', () => {
      this.updateAchievementsDisplay();
      this.showPanel('achievements');
    });

    onClick(doc, 'btn-quit', () => {
      this.game.state = GameState.Menu;
      this.gameSystem.hideGame();
      this.showPanel('menu');
    });
  }

  private wireAchievementsButtons() {
    const doc = this.achievementsDoc!;

    onClick(doc, 'btn-ach-back', () => {
      if (this.game.state === GameState.Paused) {
        this.showPanel('pause');
      } else {
        this.showPanel('menu');
      }
    });
  }

  private wireHowtoButtons() {
    const doc = this.howtoDoc!;
    onClick(doc, 'btn-howto-back', () => {
      this.showPanel('menu');
    });
  }

  private updateSettingsDisplay() {
    if (!this.settingsDoc) return;
    const diffNames = ['Easy', 'Normal', 'Hard'];
    setText(this.settingsDoc, 'diff-label', `Difficulty: ${diffNames[this.game.difficulty]}`);
    setText(this.settingsDoc, 'theme-label', `Theme: ${this.game.currentTheme.name}`);
    this.game.saveHighScores();
  }

  private updateAchievementsDisplay() {
    if (!this.achievementsDoc) return;
    const doc = this.achievementsDoc;
    setText(doc, 'ach-count', `${this.game.achievements.length} / ${this.game.totalAchievementCount} Unlocked`);

    // Show achievements in lines
    const allAchIds = Object.keys({
      first_blood: 1, bomber_10: 1, combo_3: 1, combo_5: 1, combo_10: 1,
      score_5k: 1, score_10k: 1, score_50k: 1, level_3: 1, level_5: 1, level_10: 1,
      kill_10: 1, kill_50: 1, kill_100: 1, perfect: 1, games_10: 1,
      speed_max: 1, bombs_max: 1, range_max: 1, all_powerups: 1,
      survive_5min: 1, no_damage_level: 1, blocks_100: 1, blocks_500: 1,
      enemy_bomber: 1, hard_complete: 1, timed_win: 1, survival_l5: 1,
      survival_l10: 1, total_50k: 1, chain_bomb: 1, shield_save: 1,
      remote_kill: 1, passthrough: 1, max_power: 1, quick_clear: 1,
      bomb_chain_3: 1, no_bombs_die: 1, play_all_modes: 1, score_100k: 1,
      kill_teleporter: 1, kill_patrol: 1, puzzle_complete: 1, bombs_100: 1,
      powerups_20: 1, survive_10min: 1, combo_15: 1, level_15: 1,
      blocks_1000: 1, fast_clear: 1,
    });

    for (let i = 0; i < 12; i++) {
      const achId = allAchIds[i];
      if (achId) {
        const unlocked = this.game.achievements.includes(achId);
        const name = this.game.getAchievementName(achId);
        const prefix = unlocked ? '[*] ' : '[ ] ';
        setText(doc, `ach-line-${i}`, prefix + name);
        setColor(doc, `ach-line-${i}`, unlocked ? '#00ff88' : '#446688');
      } else {
        setText(doc, `ach-line-${i}`, '');
      }
    }

    setText(doc, 'ach-stats', `Games: ${this.game.totalGames} -- Best: ${Math.floor(this.game.bestScore)} -- Total Kills: ${this.game.totalEnemiesKilled}`);
  }

  private showPanel(state: 'menu' | 'playing' | 'gameover' | 'settings' | 'victory' | 'pause' | 'achievements' | 'transition' | 'howto') {
    if (this.menuEntity) this.menuEntity.object3D!.visible = state === 'menu';
    if (this.gameoverEntity) this.gameoverEntity.object3D!.visible = state === 'gameover' || state === 'victory';
    if (this.settingsEntity) this.settingsEntity.object3D!.visible = state === 'settings';
    if (this.hudEntity) this.hudEntity.object3D!.visible = state === 'playing';
    if (this.pauseEntity) this.pauseEntity.object3D!.visible = state === 'pause';
    if (this.achievementsEntity) this.achievementsEntity.object3D!.visible = state === 'achievements';
    if (this.powerupsEntity) this.powerupsEntity.object3D!.visible = state === 'playing';
    if (this.transitionEntity) this.transitionEntity.object3D!.visible = state === 'transition';
    if (this.howtoEntity) this.howtoEntity.object3D!.visible = state === 'howto';
  }

  update(delta: number, time: number) {
    if (this.game.state !== this.lastState) {
      this.onStateChange(this.lastState, this.game.state);
      this.lastState = this.game.state;
    }

    if (this.game.state === GameState.Playing) {
      if (this.hudDoc) this.updateHUD();
      if (this.powerupsDoc) this.updatePowerUpsHUD();

      // Combo sound
      if (this.game.comboCount > this.lastCombo && this.game.comboCount > 1) {
        this.gameSystem.playComboSound(this.game.comboCount);
      }
      this.lastCombo = this.game.comboCount;

      // Multiplier sound
      if (this.game.multiplier > this.lastMultiplier) {
        this.gameSystem.playMultiplierSound(this.game.multiplier);
      }
      this.lastMultiplier = this.game.multiplier;
    }

    if (this.game.state === GameState.Paused) {
      if (this.input.keyboard.getKeyDown('Escape')) {
        this.game.state = GameState.Playing;
        this.showPanel('playing');
      }
    }

    if (this.game.state === GameState.LevelTransition) {
      if (this.transitionDoc) {
        this.updateTransitionDisplay();
      }
    }
  }

  private onStateChange(from: GameState, to: GameState) {
    if (to === GameState.GameOver) {
      this.showPanel('gameover');
      this.updateGameoverDisplay(false);
      this.gameSystem.playDeathSound();
    } else if (to === GameState.Victory) {
      this.showPanel('victory');
      this.updateGameoverDisplay(true);
      this.gameSystem.playVictorySound();
      this.game.saveHighScores();
    } else if (to === GameState.Paused) {
      this.showPanel('pause');
      this.updatePauseDisplay();
    } else if (to === GameState.Menu) {
      this.showPanel('menu');
      this.game.saveHighScores();
    } else if (to === GameState.LevelTransition) {
      this.showPanel('transition');
      this.updateTransitionDisplay();
      this.gameSystem.playLevelCompleteSound();
    } else if (to === GameState.Playing && from === GameState.LevelTransition) {
      this.showPanel('playing');
    }
  }

  private updateHUD() {
    if (!this.hudDoc) return;
    setText(this.hudDoc, 'score', `Score: ${Math.floor(this.game.score)}`);
    setText(this.hudDoc, 'lives', `Lives: ${this.game.lives}`);
    setText(this.hudDoc, 'level', `Lv ${this.game.level}`);

    if (this.game.mode === GameMode.Timed || this.game.mode === GameMode.Puzzle) {
      const remaining = Math.max(0, this.game.timeLimit - this.game.timeElapsed);
      const min = Math.floor(remaining / 60);
      const sec = Math.floor(remaining % 60);
      setText(this.hudDoc, 'timer', `${min}:${sec.toString().padStart(2, '0')}`);
      // Color warning
      if (remaining < 30) {
        setColor(this.hudDoc, 'timer', '#ff4444');
      } else if (remaining < 60) {
        setColor(this.hudDoc, 'timer', '#ffcc00');
      } else {
        setColor(this.hudDoc, 'timer', '#88ccff');
      }
    } else {
      const min = Math.floor(this.game.timeElapsed / 60);
      const sec = Math.floor(this.game.timeElapsed % 60);
      setText(this.hudDoc, 'timer', `${min}:${sec.toString().padStart(2, '0')}`);
    }

    if (this.game.comboCount > 1) {
      setText(this.hudDoc, 'combo', `x${this.game.comboCount} COMBO`);
    } else {
      setText(this.hudDoc, 'combo', '');
    }

    if (this.game.multiplier > 1) {
      setText(this.hudDoc, 'multiplier', `x${this.game.multiplier} MULTI`);
    } else {
      setText(this.hudDoc, 'multiplier', '');
    }
  }

  private updatePowerUpsHUD() {
    if (!this.powerupsDoc) return;
    setText(this.powerupsDoc, 'pu-bombs', `B:${this.game.maxBombs}`);
    setText(this.powerupsDoc, 'pu-range', `R:${this.game.blastRange}`);
    setText(this.powerupsDoc, 'pu-speed', `S:${this.game.speed.toFixed(1)}`);
    setColor(this.powerupsDoc, 'pu-pass', this.game.hasPassThrough ? '#8888ff' : '#555555');
    setColor(this.powerupsDoc, 'pu-remote', this.game.hasRemoteDetonate ? '#ff00ff' : '#555555');
    const shieldActive = this.game.hasShield && this.game.shieldTimer > 0;
    setColor(this.powerupsDoc, 'pu-shield', shieldActive ? '#00ffff' : '#555555');
  }

  private updatePauseDisplay() {
    if (!this.pauseDoc) return;
    setText(this.pauseDoc, 'pause-score', `Score: ${Math.floor(this.game.score)}`);
    setText(this.pauseDoc, 'pause-level', `Level ${this.game.level}`);
    const min = Math.floor(this.game.timeElapsed / 60);
    const sec = Math.floor(this.game.timeElapsed % 60);
    setText(this.pauseDoc, 'pause-time', `${min}:${sec.toString().padStart(2, '0')}`);
  }

  private updateTransitionDisplay() {
    if (!this.transitionDoc) return;
    setText(this.transitionDoc, 'transition-text', `LEVEL ${this.game.level + 1}`);
    setText(this.transitionDoc, 'transition-bonus', `+${(this.game.level + 1) * 500} Level Bonus`);
    const enemyCount = this.game.getEnemyCountForNextLevel();
    setText(this.transitionDoc, 'transition-enemies', `${enemyCount} enemies incoming`);
  }

  private updateGameoverDisplay(victory: boolean) {
    if (!this.gameoverDoc) return;
    setText(this.gameoverDoc, 'title', victory ? 'VICTORY!' : 'GAME OVER');
    setText(this.gameoverDoc, 'final-score', `Score: ${Math.floor(this.game.score)}`);
    setText(this.gameoverDoc, 'stats', `Level ${this.game.level} -- Enemies: ${this.game.enemiesKilled} -- Blocks: ${this.game.blocksDestroyed}`);
    setText(this.gameoverDoc, 'best-score', `Best: ${Math.floor(this.game.bestScore)}`);

    const newAchievements = this.game.achievements.slice(-3);
    if (newAchievements.length > 0) {
      const names = newAchievements.map(id => this.game.getAchievementName(id)).join(', ');
      setText(this.gameoverDoc, 'achievements', `Unlocked: ${names}`);
    } else {
      setText(this.gameoverDoc, 'achievements', `Achievements: ${this.game.achievements.length}/${this.game.totalAchievementCount}`);
    }
  }
}

import {
  World,
  PanelUI,
  Follower,
} from '@iwsdk/core';

async function main() {
  const container = document.getElementById('app') as HTMLDivElement;

  const world = await World.create(container, {
    xr: { offer: 'once' },
    input: { canvasPointerEvents: true },
    render: {
      near: 0.01,
      far: 200,
      defaultLighting: false,
      camera: { position: [0, 8, 6], lookAt: [0, 0, 0] },
    },
    features: {
      grabbing: false,
      locomotion: { browserControls: true },
      physics: false,
      spatialUI: true,
    },
  });

  // Import systems dynamically to keep index clean
  const { GameManager } = await import('./game');
  const { GameSystem } = await import('./game-system');
  const { GameUISystem } = await import('./ui-system');

  const game = new GameManager();

  // Register systems
  world.registerSystem(GameSystem);
  world.registerSystem(GameUISystem);

  const gameSystem = world.getSystem(GameSystem)!;
  gameSystem.setRefs({ game });

  const uiSystem = world.getSystem(GameUISystem)!;
  uiSystem.setRefs({ game, gameSystem });

  // Setup scene
  gameSystem.setupScene();

  // Create HUD panel (head-locked)
  const hudEntity = world.createTransformEntity(undefined, {
    parent: world.playerHeadEntity,
    persistent: true,
  });
  hudEntity.addComponent(PanelUI, { config: './ui/hud.json' });
  hudEntity.addComponent(Follower);
  const fOff = hudEntity.getVectorView(Follower, 'offsetPosition');
  fOff[0] = 0; fOff[1] = 0.22; fOff[2] = -0.6;

  // Create power-ups HUD (head-locked, below main HUD)
  const powerupsEntity = world.createTransformEntity(undefined, {
    parent: world.playerHeadEntity,
    persistent: true,
  });
  powerupsEntity.addComponent(PanelUI, { config: './ui/powerups.json' });
  powerupsEntity.addComponent(Follower);
  const puOff = powerupsEntity.getVectorView(Follower, 'offsetPosition');
  puOff[0] = 0; puOff[1] = 0.15; puOff[2] = -0.6;

  // Create menu panel (world-space, in front of player)
  const menuEntity = world.createTransformEntity();
  menuEntity.object3D!.position.set(0, 4, -2);
  menuEntity.addComponent(PanelUI, { config: './ui/menu.json' });

  // Create game-over panel (world-space, hidden initially)
  const gameoverEntity = world.createTransformEntity();
  gameoverEntity.object3D!.position.set(0, 4, -2);
  gameoverEntity.object3D!.visible = false;
  gameoverEntity.addComponent(PanelUI, { config: './ui/gameover.json' });

  // Create settings panel
  const settingsEntity = world.createTransformEntity();
  settingsEntity.object3D!.position.set(0, 4, -2);
  settingsEntity.object3D!.visible = false;
  settingsEntity.addComponent(PanelUI, { config: './ui/settings.json' });

  // Create pause panel
  const pauseEntity = world.createTransformEntity();
  pauseEntity.object3D!.position.set(0, 4, -2);
  pauseEntity.object3D!.visible = false;
  pauseEntity.addComponent(PanelUI, { config: './ui/pause.json' });

  // Create achievements panel
  const achievementsEntity = world.createTransformEntity();
  achievementsEntity.object3D!.position.set(0, 4, -2);
  achievementsEntity.object3D!.visible = false;
  achievementsEntity.addComponent(PanelUI, { config: './ui/achvmts.json' });

  // Create level transition panel (head-locked, center)
  const transitionEntity = world.createTransformEntity(undefined, {
    parent: world.playerHeadEntity,
    persistent: true,
  });
  transitionEntity.addComponent(PanelUI, { config: './ui/leveltransition.json' });
  transitionEntity.addComponent(Follower);
  const trOff = transitionEntity.getVectorView(Follower, 'offsetPosition');
  trOff[0] = 0; trOff[1] = 0; trOff[2] = -0.8;
  transitionEntity.object3D!.visible = false;

  // Create how-to-play panel
  const howtoEntity = world.createTransformEntity();
  howtoEntity.object3D!.position.set(0, 4, -2);
  howtoEntity.object3D!.visible = false;
  howtoEntity.addComponent(PanelUI, { config: './ui/howto.json' });

  uiSystem.setPanelEntities(
    hudEntity, menuEntity, gameoverEntity, settingsEntity,
    pauseEntity, achievementsEntity, powerupsEntity, transitionEntity,
    howtoEntity
  );
}

main();

